func (s *libraryService_ShelfServer) CreateShelf(ctx context.Context, request *v11.CreateShelfRequest) (*v13.Shelf, error) {
	// STEP 1: Set identifiers.
	if request.RequestId == "" { // We always set a request id
		request.RequestId = uuid.MustNewV7().String()
	}
	shelfId := request.ShelfId
	if shelfId == "" {
		shelfId = aip.NewSystemGeneratedBase32ResourceID()
	}

	var organizationId string
	if resourcename.ContainsWildcard(request.Parent) {
		return nil, status.Errorf(codes.InvalidArgument, "parent cannot contain wildcard").Err()
	}
	if err := resourcename.Sscan(request.Parent, "organizations/{organization}", &organizationId); err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "invalid parent name: %v", err).Err()
	}

	request.Shelf.Name = resourcename.Sprint("organizations/{organization}/shelves/{shelf}", organizationId, shelfId)

	// STEP 2: Instantiate timestamps.
	// Check for x-migration-request header
	if values := metadata.ValueFromIncomingContext(ctx, "x-migration-request"); len(values) > 0 {
		if request.Shelf.CreateTime == nil {
			return nil, status.Errorf(codes.InvalidArgument, "x-migration-request used without setting a create_time").Err()
		}
	} else {
		request.Shelf.CreateTime = timestamppb.Now()
	}
	request.Shelf.UpdateTime = request.Shelf.CreateTime

	// STEP 3: Convert the resource to the database representation.
	shelfModel, err := model.ShelfFromPb(request.Shelf)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from pb to model: %v", err).Err()
	}

	if request.ValidateOnly {
		return request.Shelf, nil
	}

	// STEP 4: Insert the resource idempotently.
	dbShelfModel, err := s.store.InsertShelfIdempotently(ctx, request.RequestId, shelfModel)
	if err != nil {
		if errors.Is(err, model.ErrShelfAlreadyExists) {
			return nil, status.Errorf(codes.AlreadyExists, "shelf already exists").Err()
		}
		return nil, status.FromError(err, "inserting shelf").Err()
	}

	shelf, err := dbShelfModel.ToPb()
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from model to pb: %v", err).Err()
	}

	// STEP 5: Publish events.
	{
		subject := v13.GetShelfStream().GetCreatedSubject()
		if err := subject.Publish(ctx, s.natsClient, shelf); err != nil {
			return nil, status.Errorf(codes.Internal, "publishing created event: %v", err).Err()
		}
	}
	return shelf, nil
}

func (s *libraryService_ShelfServer) GetShelf(ctx context.Context, request *v11.GetShelfRequest) (*v13.Shelf, error) {
	if resourcename.ContainsWildcard(request.Name) {
		return nil, status.Errorf(codes.InvalidArgument, "cannot use wildcard").Err()
	}

	organizationId, shelfId, err := model.ParseShelfName(request.Name)
	if err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "parsing name: %v", err).Err()
	}

	// Retrieve from the database.
	dbShelfModel, err := s.store.GetShelf(ctx, organizationId, shelfId)
	if err != nil {
		if errors.Is(err, model.ErrShelfNotExist) {
			return nil, status.Errorf(codes.NotFound, "shelf does not exist").Err()
		}
		return nil, status.FromError(err, "getting shelf").Err()
	}

	shelf, err := dbShelfModel.ToPb()
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from model to pb: %v", err).Err()
	}
	return shelf, nil
}

var updateShelfRequestParser = aip.MustNewUpdateRequestParser[*v11.UpdateShelfRequest, *v13.Shelf]()

func (s *libraryService_ShelfServer) UpdateShelf(ctx context.Context, request *v11.UpdateShelfRequest) (*v13.Shelf, error) {
	if len(request.GetUpdateMask().GetPaths()) == 0 {
		return nil, status.Errorf(codes.InvalidArgument, "missing update_mask.paths").Err()
	}
	if resourcename.ContainsWildcard(request.Shelf.Name) {
		return nil, status.Errorf(codes.InvalidArgument, "cannot use wildcard").Err()
	}

	// STEP 1: Parse request.
	parsedRequest, err := updateShelfRequestParser.Parse(request)
	if err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "parsing request: %v", err).Err()
	}

	// STEP 2: retrieve existing resource.
	getShelfRequest := &v11.GetShelfRequest{Name: request.Shelf.Name}
	existingShelf, err := s.GetShelf(ctx, getShelfRequest)
	if err != nil {
		return nil, err
	}
	// Verify that the resource is not soft deleted
	if existingShelf.DeleteTime != nil {
		return nil, status.Errorf(codes.NotFound, "shelf does not exist").Err()
	}

	// STEP 3: Patch the existing resource.
	patchedShelf := proto.CloneOf(existingShelf)
	parsedRequest.ApplyFieldMask(patchedShelf, request.Shelf)
	if err := protovalidate.Validate(patchedShelf); err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "validating patched resource: %v", err).Err()
	}

	// Set the update time.
	patchedShelf.UpdateTime = timestamppb.Now()
	// STEP 4: Insert patched resource.
	shelfModel, err := model.ShelfFromPb(patchedShelf)
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from pb to model: %v", err).Err()
	}
	dbShelfModel, err := s.store.UpdateShelf(ctx, shelfModel, parsedRequest.GetSQLUpdateClause(), parsedRequest.GetSQLColumns())
	if err != nil {
		if errors.Is(err, model.ErrShelfNotExist) {
			return nil, status.Errorf(codes.NotFound, "shelf does not exist").Err()
		}
		return nil, status.FromError(err, "updating shelf").Err()
	}

	shelf, err := dbShelfModel.ToPb()
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from model to pb: %v", err).Err()
	}

	// STEP 5: Publish events.
	{
		subject := v13.GetShelfStream().GetUpdatedSubject()
		if err := subject.Publish(ctx, s.natsClient, shelf, existingShelf, request.GetUpdateMask()); err != nil {
			return nil, status.Errorf(codes.Internal, "publishing updated event: %v", err).Err()
		}
	}
	{
		subject := v13.GetShelfStream().GetGenreChangeSubject()
		if err := subject.Publish(ctx, s.natsClient, shelf, existingShelf, request.GetUpdateMask()); err != nil {
			return nil, status.Errorf(codes.Internal, "publishing genre_change event: %v", err).Err()
		}
	}
	return shelf, nil
}

func (s *libraryService_ShelfServer) publishResourceDeletedEvent(ctx context.Context, shelf *v13.Shelf) error {
	{
		subject := v13.GetShelfStream().GetDeletedSubject()
		if err := subject.Publish(ctx, s.natsClient, shelf); err != nil {
			return status.Errorf(codes.Internal, "publishing deleted event: %v", err).Err()
		}
	}
	return nil
}

func (s *libraryService_ShelfServer) DeleteShelf(ctx context.Context, request *v11.DeleteShelfRequest) (*v13.Shelf, error) {
	if resourcename.ContainsWildcard(request.Name) {
		return nil, status.Errorf(codes.InvalidArgument, "cannot use wildcard").Err()
	}

	// STEP 1: Parse resource name.
	organizationId, shelfId, err := model.ParseShelfName(request.Name)
	if err != nil {
		return nil, status.Errorf(codes.InvalidArgument, "parsing name: %v", err).Err()
	}

	deleteTime := time.Now().UTC()
	// STEP 2: Soft delete the resource.
	dbShelfModel, err := s.store.SoftDeleteShelf(ctx, organizationId, shelfId, deleteTime)
	if err != nil {
		if errors.Is(err, model.ErrShelfNotExist) {
			return nil, status.Errorf(codes.NotFound, "shelf does not exist").Err()
		}
		if errors.Is(err, model.ErrShelfAlreadyDeleted) {
			if request.AllowMissing {
				getShelfRequest := &v11.GetShelfRequest{Name: request.Name}
				shelf, err := s.GetShelf(ctx, getShelfRequest)
				if err != nil {
					return nil, err
				}
				if err := s.publishResourceDeletedEvent(ctx, shelf); err != nil {
					return nil, err
				}
				return shelf, nil
			}
			return nil, status.Errorf(codes.NotFound, "shelf already deleted").Err()
		}
		return nil, status.FromError(err, "soft deleting shelf").Err()
	}

	// STEP 3: Convert to protobuf and return.
	shelf, err := dbShelfModel.ToPb()
	if err != nil {
		return nil, status.Errorf(codes.Internal, "converting shelf from model to pb: %v", err).Err()
	}

	// STEP 4: Publish event.
	if err := s.publishResourceDeletedEvent(ctx, shelf); err != nil {
		return nil, err
	}

	return shelf, nil
}

